INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'db0cc356-3b5c-4a51-ab13-57e010ed1880',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack Config — Zero-Config Defaults vs. Explicit webpack.config.js$escape$,
  $escape$webpack 4+ ships with production/development mode defaults that eliminate boilerplate for simple projects: run `webpack --mode production` and you get Terser minification, tree-shaking via `optimization.usedExports`, and deterministic chunk IDs — no config file needed. But the moment you need custom loaders, multiple entry points, or output path control, you need `webpack.config.js`.

The config file exports a plain object (or a function for env-aware configs). `entry` defaults to `./src/index.js`; `output.path` defaults to `./dist`. Override only what you must — webpack merges your explicit keys with the mode defaults, not replaces them entirely.

For team projects, prefer the functional form: `module.exports = (env, argv) => ({})`. `argv.mode` gives you `'production'` or `'development'` so you can conditionally enable `devtool: 'source-map'` without separate config files. Use `webpack-merge` to split base/dev/prod configs only when differences grow beyond 20–30 lines — premature splitting adds navigation overhead with no real benefit.$escape$,
  $escape$// webpack.config.js — functional form, env-aware
const { merge } = require('webpack-merge');

module.exports = (env, argv) => ({
  entry: './src/index.ts',
  output: {
    filename: '[name].[contenthash].js',
    path: __dirname + '/dist',
    clean: true,
  },
  resolve: { extensions: ['.ts', '.js'] },
  module: {
    rules: [{ test: /\.ts$/, use: 'ts-loader', exclude: /node_modules/ }],
  },
  devtool: argv.mode === 'production' ? false : 'eval-source-map',
});$escape$,
  $escape$javascript$escape$,
