INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'acdeae3a-0482-4484-984b-9d41e383dc14',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack Dev Server — HMR, Proxy Setup, and HTTPS in Dev$escape$,
  $escape$webpack-dev-server's `devServer` config block controls three critical dev-time behaviors. HMR (Hot Module Replacement) is enabled by default in webpack 5 when `hot: true`; it patches modules in-place via `webpack/hot/dev-server` without a full page reload, preserving component state. For API proxying, `devServer.proxy` delegates matching routes to your backend — essential when your frontend runs on port 3000 but your API lives on 5000. The `pathRewrite` option strips prefixes before forwarding. For HTTPS, `devServer.server: 'https'` spins up a local TLS server using webpack-dev-server's self-signed cert; swap in your own via `server: { type: 'https', options: { key, cert } }`. Combine this with `allowedHosts: 'all'` cautiously — it disables the host check that prevents DNS rebinding attacks. In webpack 5, `devServer.client.webSocketURL` must match your HTTPS scheme so the HMR websocket doesn't get blocked by mixed-content policies.$escape$,
  $escape$// webpack.config.js
module.exports = {
  devServer: {
    hot: true,
    server: {
      type: 'https',
      options: {
        key: './certs/localhost-key.pem',
        cert: './certs/localhost.pem',
      },
    },
    client: {
      webSocketURL: 'wss://localhost:3000/ws',
    },
    proxy: [
      {
        context: ['/api'],
        target: 'http://localhost:5000',
        pathRewrite: { '^/api': '' },
        changeOrigin: true,
      },
    ],
  },
};$escape$,
