INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '51c12ef9-e413-47d2-8e8d-db9fce5d3504',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack Bundle Analysis — Visualizing Size, Finding Bloat, and Enforcing CI Budgets$escape$,
  $escape$webpack's stats JSON is your starting point. Run `webpack --json > stats.json` and feed it into `webpack-bundle-analyzer` to get an interactive treemap of every module by parsed and gzipped size. Spot immediately when a lodash import pulls in 70 kB because you forgot `babel-plugin-lodash` or a dynamic `import()` boundary got swallowed into the main chunk.

For deeper audits, `--profile` flags each module's build time alongside its size — useful when a single dependency balloons after a version bump.

To enforce limits in CI, use `performance` in your webpack config. Set `hints: 'error'` so the build fails on violations instead of just warning. Pair `maxEntrypointSize` and `maxAssetSize` (in bytes) to gate merges on bundle discipline.

For per-chunk granularity, `SpeedMeasurePlugin` combined with a custom `BundleAnalyzerPlugin` in `server` mode lets you diff bundle reports between branches — run `webpack-bundle-analyzer stats.json` in headless mode and compare the generated HTML artifacts in your CI artifacts tab.$escape$,
  $escape$// webpack.config.js
const { BundleAnalyzerPlugin } = require('webpack-bundle-analyzer');

module.exports = {
  performance: {
    hints: process.env.CI ? 'error' : 'warning',
    maxEntrypointSize: 250_000,  // 250 kB
    maxAssetSize: 200_000,       // 200 kB
  },
  plugins: [
    new BundleAnalyzerPlugin({
      analyzerMode: process.env.ANALYZE ? 'server' : 'disabled',
      generateStatsFile: true,
      statsFilename: 'stats.json',
    }),
  ],
};$escape$,
  $escape$javascript$escape$,
