INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd276bac6-0f45-4c77-bd52-21759e80d7f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack + TypeScript — Transpile-Only vs Type-Check: Pick Your Trade-off$escape$,
  $escape$webpack doesn't type-check TypeScript by default — it just transpiles. ts-loader runs tsc under the hood and blocks your build on type errors, giving you safety but costing seconds on every rebuild. babel-loader with @babel/preset-typescript strips types at parse time, no tsc invoked, which makes it 2–5x faster in large projects. The catch: Babel silently ignores type errors entirely.

The practical webpack pattern: use babel-loader in development for fast HMR, and run tsc --noEmit as a parallel npm script or in a ForkTsCheckerWebpackPlugin worker so type errors surface without blocking the main bundle graph. ForkTsCheckerWebpackPlugin spawns a separate process and reports errors as webpack overlay diagnostics — you get near-babel speed with incremental type checking.

In CI, swap to ts-loader with transpileOnly: false to enforce full type safety before merge. Never ship a webpack config that skips type-checking entirely in CI — transpile-only is a dev ergonomics optimization, not a production default.$escape$,
  $escape$// webpack.config.ts
import ForkTsCheckerWebpackPlugin from 'fork-ts-checker-webpack-plugin';

const isDev = process.env.NODE_ENV === 'development';

export default {
  module: {
    rules: [{
      test: /\.tsx?$/,
      use: isDev
        ? { loader: 'babel-loader' }                        // transpile-only, fast HMR
        : { loader: 'ts-loader', options: { transpileOnly: false } }, // full type-check in CI
      exclude: /node_modules/,
    }],
  },
  plugins: isDev
    ? [new ForkTsCheckerWebpackPlugin()]  // async type errors, non-blocking
    : [],
};$escape$,
  $escape$typescript$escape$,
