INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '23053ec7-57bd-49bd-97e4-cadb444e3fbd',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack Persistent Caching — Cutting Rebuild Times by 90%$escape$,
  $escape$webpack 5's filesystem cache (`cache.type: 'filesystem'`) serializes the module graph, chunk graph, and code generation results to disk between builds. On a cold run, webpack processes every module. On subsequent runs, it only reprocesses modules whose content hash changed — skipping the resolve, parse, and transform pipeline for everything else. The cache lives in `node_modules/.cache/webpack` by default and is keyed by a `buildDependencies.config` hash, so it automatically invalidates when your `webpack.config.js` changes.

Pair this with `cache.version` to namespace caches across branches, preventing cross-contamination. For parallelism, `thread-loader` offloads expensive loaders (babel-loader, ts-loader) to a worker pool — place it immediately before the target loader. Use `thread-loader`'s `warmup()` in your config to pre-spawn workers before the build starts, eliminating the thread startup penalty on the first run. Together, filesystem caching + `thread-loader` targeting your heaviest loaders consistently brings incremental rebuilds from 30s+ to under 3s on mid-size TypeScript monorepos.$escape$,
  $escape$// webpack.config.js
const { warmup } = require('thread-loader');

warmup({ workers: 2 }, ['babel-loader', 'ts-loader']);

module.exports = {
  cache: {
    type: 'filesystem',
    version: process.env.GIT_BRANCH || 'default',
    buildDependencies: { config: [__filename] },
  },
  module: {
    rules: [{
      test: /\.tsx?$/,
      use: ['thread-loader', 'ts-loader'],
    }],
  },
};$escape$,
  $escape$javascript$escape$,
